class MyClass:
    class_var = 0

    def __init__(self, value):
        self.value = value
        MyClass.class_var += 1

    def instance_method(self):
        return f"Instance: {self.value}"

    @classmethod
    def class_method(cls):
        return f"Class var: {cls.class_var}"

    @staticmethod
    def static_method(x):
        return x * 2

a = MyClass(10)
b = MyClass(20)

print(a.instance_method())
print(MyClass.class_method())
print(MyClass.static_method(5))
